-- Legacy seasons 1-3 import (Google Sheets -> bot DB). Generated 2026-07-05.
-- Run AFTER a WAL-safe backup. Single transaction: any error rolls everything back.
BEGIN;
UPDATE seasons SET number=4 WHERE status='active' AND chat_id=(SELECT chat_id FROM chats LIMIT 1);
VALUES(-1, (SELECT chat_id FROM chats LIMIT 1), 1, 100, '[3,1,0]', 'archived', (SELECT id FROM players WHERE chat_id=(SELECT chat_id FROM chats LIMIT 1) AND name='Nur'), '2025-10-25 07:00:00', '2025-11-12 20:00:00');
VALUES(-2, (SELECT chat_id FROM chats LIMIT 1), 2, 100, '[3,1,0]', 'archived', (SELECT id FROM players WHERE chat_id=(SELECT chat_id FROM chats LIMIT 1) AND name='Nur'), '2025-11-17 07:00:00', '2025-12-02 20:00:00');
VALUES(-3, (SELECT chat_id FROM chats LIMIT 1), 3, 100, '[3,1,0]', 'archived', (SELECT id FROM players WHERE chat_id=(SELECT chat_id FROM chats LIMIT 1) AND name='mister'), '2025-12-06 07:00:00', '2026-01-05 20:00:00');
COMMIT;

-- ===== VERIFICATION (expected vs actual; diff column must be all-zero) =====
SELECT 'games total' k, (SELECT COUNT(*) FROM games WHERE id < 0) actual, 222 expected;
SELECT 's1 Joe Rude' k, COALESCE(SUM(gr.points),0)||'/'||SUM(gr.rank=1)||'/'||COUNT(*) actual, '69/22/63' expected FROM game_results gr JOIN games g ON g.id=gr.game_id WHERE g.season_id=-1 AND gr.player_id=(SELECT id FROM players WHERE chat_id=(SELECT chat_id FROM chats LIMIT 1) AND name='Joe Rude');
